from openfeature import api
from openfeature.provider.in_memory_provider import InMemoryProvider, InMemoryFlag

# --- Registration (done once at app startup) ---
flags = {
    "new-planner-v2": InMemoryFlag(
        default_variant="off",
        variants={"on": True, "off": False},
        flag_metadata={"owner": "ai-platform", "expires": "2026-08-01"},
    )
}
api.set_provider(InMemoryProvider(flags))
client = api.get_client()

# --- Usage in agent code ---
def plan_steps(user_query: str, user_context: dict) -> list[str]:
    use_new_planner = client.get_boolean_value(
        flag_key="new-planner-v2",
        default_value=False,
        evaluation_context=user_context,  # targeting rules apply here
    )
    if use_new_planner:
        return new_planner_v2(user_query)
    else:
        return legacy_planner(user_query)

# --- Unit test for the ON path ---
def test_new_planner_selected_when_flag_on(monkeypatch):
    monkeypatch.setattr(
        "myagent.planner.client.get_boolean_value",
        lambda **_: True,
    )
    result = plan_steps("Book a flight", {})
    assert len(result) > 0  # new planner must return steps

