# ci/check_flags.py  — run in CI to enforce lifecycle metadata
import os, httpx, ast, pathlib

FLAG_API = os.environ["FLAG_API_URL"]
FLAG_API_TOKEN = os.environ["FLAG_API_TOKEN"]

def flags_in_source(root: str) -> set[str]:
    """Extract all flag key literals from Python source files."""
    keys = set()
    for p in pathlib.Path(root).rglob("*.py"):
        try:
            tree = ast.parse(p.read_text())
        except SyntaxError:
            continue
        for node in ast.walk(tree):
            if isinstance(node, ast.Call):
                for kw in node.keywords:
                    if kw.arg == "flag_key" and isinstance(kw.value, ast.Constant):
                        keys.add(kw.value.value)
    return keys

def registered_flags() -> dict:
    resp = httpx.get(
        f"{FLAG_API}/flags",
        headers={"Authorization": f"Bearer {FLAG_API_TOKEN}"},
    )
    resp.raise_for_status()
    return {f["key"]: f for f in resp.json()}

if __name__ == "__main__":
    source_flags = flags_in_source("src/")
    registered = registered_flags()
    errors = []
    for key in source_flags:
        if key not in registered:
            errors.append(f"Flag '{key}' used in source but not registered")
        else:
            meta = registered[key].get("_meta", {})
            if not meta.get("expires"):
                errors.append(f"Flag '{key}' has no expiry date")
            if not meta.get("owner"):
                errors.append(f"Flag '{key}' has no owner")
    if errors:
        for e in errors:
            print(f"ERROR: {e}")
        raise SystemExit(1)
    print(f"All {len(source_flags)} flags are registered and have metadata.")
